<template><div><div class="page-head"><div><h1>Phí phạt</h1><p>Quản lý công nợ, thu phí phạt và theo dõi trạng thái thanh toán</p></div><button class="btn primary" :disabled="!selected" @click="paySelected"><i class="mdi mdi-cash-check"></i>Thu phí</button></div><div v-if="error" class="alert error">{{error}}</div><div v-if="success" class="alert success">{{success}}</div><div class="grid grid-4"><div class="card stat"><div class="stat-icon blue"><i class="mdi mdi-wallet"></i></div><div><div class="stat-label">Tổng công nợ</div><div class="stat-value">{{formatMoney(total)}}</div></div></div><div class="card stat"><div class="stat-icon red"><i class="mdi mdi-alert"></i></div><div><div class="stat-label">Chưa thanh toán</div><div class="stat-value">{{formatMoney(unpaid)}}</div></div></div><div class="card stat"><div class="stat-icon green"><i class="mdi mdi-check-circle"></i></div><div><div class="stat-label">Đã thu</div><div class="stat-value">{{formatMoney(paid)}}</div></div></div><div class="card stat"><div class="stat-icon purple"><i class="mdi mdi-percent"></i></div><div><div class="stat-label">Miễn giảm</div><div class="stat-value">0 đ</div></div></div></div><div class="split" style="margin-top:16px"><section class="card pad"><div class="toolbar"><div class="field"><label>Tìm kiếm</label><input class="input" v-model="q" placeholder="Bạn đọc, mã phiếu, mã phạt"></div><div class="field"><label>Trạng thái</label><select class="select" v-model="status"><option value="">Tất cả</option><option value="1">Chưa thu</option><option value="2">Một phần</option><option value="3">Đã thu</option></select></div></div><div class="table-wrap" style="margin-top:16px"><table><thead><tr><th>Mã phạt</th><th>Độc giả</th><th>Tổng</th><th>Đã thu</th><th>Còn nợ</th><th>Trạng thái</th><th></th></tr></thead><tbody><tr v-for="f in filtered" :key="f.id"><td>{{f.fineCode}}</td><td>{{f.readerName}}<br><small>{{f.readerCode}}</small></td><td>{{formatMoney(f.totalAmount)}}</td><td>{{formatMoney(f.paidAmount)}}</td><td>{{formatMoney(f.remainingAmount)}}</td><td><span class="badge" :class="Number(f.status)===3?'green':Number(f.status)===2?'blue':'orange'">{{enumText(f.status,statusMaps.fine)}}</span></td><td><button class="mini" @click="selected=f">Chọn</button></td></tr><tr v-if="!filtered.length"><td colspan="7" class="empty">Không có khoản phí phạt.</td></tr></tbody></table></div></section><section class="card pad"><h2 class="section-title">Thu phí</h2><div v-if="selected" class="info-list"><div class="info-row"><span>Mã phạt</span><b>{{selected.fineCode}}</b></div><div class="info-row"><span>Độc giả</span><b>{{selected.readerName}}</b></div><div class="info-row"><span>Còn nợ</span><b>{{formatMoney(selected.remainingAmount)}}</b></div><div class="field"><label>Số tiền thu</label><input class="input" type="number" v-model.number="amount"></div><div class="field"><label>Phương thức</label><select class="select" v-model="method"><option>Tiền mặt</option><option>Chuyển khoản</option></select></div></div><div v-else class="empty">Chọn khoản phí để thu.</div></section></div></div></template>
<script setup>
import {computed,onMounted,ref,watch} from 'vue'
import {circulationApi,dataOf,getErrorMessage,formatMoney,enumText,statusMaps} from '../services/api'
const fines=ref([]),q=ref(''),status=ref(''),selected=ref(null),amount=ref(0),method=ref('Tiền mặt'),error=ref(''),success=ref('')
const total=computed(()=>fines.value.reduce((s,f)=>s+Number(f.totalAmount||0),0)), paid=computed(()=>fines.value.reduce((s,f)=>s+Number(f.paidAmount||0),0)), unpaid=computed(()=>fines.value.reduce((s,f)=>s+Number(f.remainingAmount||0),0))
const filtered=computed(()=>fines.value.filter(f=>(!status.value||String(f.status)===status.value)&&(!q.value||[f.fineCode,f.readerName,f.readerCode].join(' ').toLowerCase().includes(q.value.toLowerCase()))))
watch(selected,v=>amount.value=Number(v?.remainingAmount||0))
async function paySelected(){if(!selected.value||!amount.value)return;try{await circulationApi.payFine(selected.value.id,{amount:amount.value,paymentMethod:method.value});success.value='Thu phí thành công.';selected.value=null;await load()}catch(e){error.value=getErrorMessage(e,'Thu phí thất bại.')}} async function load(){fines.value=dataOf(await circulationApi.fines())}
onMounted(load)
</script>
